#include <bits/stdc++.h>
using namespace std;

bool isp(int n) {
	if (n == 2)
		return 1;
	if (n % 2 == 0) 
		return 0;
	for (int i = 3; i*i<=n; i += 2) {
		if (n % i == 0)
			return 0;
	}
	return 1;
}

int main(){
	int a;
	cin>>a;
	int b[a];
	int len=0;
	for (int i = 2; i <= a; ++i) {
		if (isp(i)) {
			b[len] = i;
			len++;
		}
	}
	for(int i=0;i<len;i++){
		for(int j=0;j<len;j++){
			for(int k=0;k<len;k++){
				if((b[i]+b[j]+b[k])==a){
					cout<<b[i]<<" "<<b[j]<<" "<<b[k];
					return 0;
				}
			}
		}
	}
	
	return 0;
}
